public class S2P01 {
    static int trecho(int v2) {
        int v1 = v2++;
        return v1 + v2;
    }

    public static void main(String[] args) {
        System.out.println(trecho(3));
    }
}

public class S2P02 {
    static int trecho(boolean ativo) {
        int x = 1;
        if (ativo) {
            x++;
        }
        return x;
    }

    public static void main(String[] args) {
        System.out.println(trecho(true));
    }
}

public class S2P03 {
    static int trecho(int v1) {
        int v2 = (v1 == 3) ? 2 : 1;
        return v2 + v1;
    }

    public static void main(String[] args) {
        System.out.println(trecho(3));
    }
}

public class S2P04 {
    static int trecho(boolean cond) {
        int x = 0;
